def gcdOfStrings(self, str1: str, str2: str) -> str:
    n = len(str1)
    m = len(str2)
    if n == 0 or m == 0:
        return ""
    if n == 1:
        return str1
    if m == 1:
        return str2

    if str1[0] == str2[0]:
        return gcdOfStrings(str1[1:], str2[1:])

    if str1[0] < str2[0]:
        return gcdOfStrings(str1[1:], str2)
    return gcdOfStrings(str1, str2[1:])

